        if (matches.Count == 0)
        {
            return input;
        }

        var sb = new StringBuilder(input.Length + matches.Count);
        bool allUpperOrSpace = true;
        bool hasSpace = false;

        for (int i = 0; i < matches.Count; i++)
        {
            if (i > 0)
            {
                sb.Append(' ');
                hasSpace = true;
