public static string Dehumanize(this string input)
{
    var words = input.Split(' ', StringSplitOptions.RemoveEmptyEntries);
    if (words.Length == 0)
    {
        return input;
    }

    if (words.Length == 1)
    {
        return words[0].Pascalize();
    }

    var sb = new StringBuilder(input.Length);
    for (int i = 0; i < words.Length; i++)
    {
        sb.Append(words[i].Pascalize());
    }
    return sb.ToString();
}

/// <summary>
/// Converts a string to PascalCase by capitalizing the first letter of each word
/// and removing separators.
/// </summary>
/// <param name="input">The string to pascalize.</param>
/// <returns>A PascalCase representation of the input.</returns>
public static string Pascalize(this string input)
{
    if (string.IsNullOrEmpty(input))
    {
        return input;
    }

    var humanized = input.Humanize();
    var titleCased = humanized.Transform(To.TitleCase);

    // Remove spaces without allocating when there are none
    if (!titleCased.Contains(' '))
    {
        return titleCased;
    }

    var sb = new StringBuilder(titleCased.Length);
    for (int i = 0; i < titleCased.Length; i++)
    {
        if (titleCased[i] != ' ')
        {
            sb.Append(titleCased[i]);
        }
    }
    return sb.ToString();
}

