/// <summary>
/// Transforms a string using a single transformer.
/// </summary>
public static string Transform(this string input, IStringTransformer transformer) =>
    transformer.Transform(input);

/// <summary>
/// Transforms a string using two transformers, applied in order.
/// </summary>
public static string Transform(this string input, IStringTransformer first, IStringTransformer second) =>
    second.Transform(first.Transform(input));

/// <summary>
/// Transforms a string using the provided transformers, applied in order.
/// </summary>
/// <param name="input">The string to transform.</param>
/// <param name="transformers">One or more transformers to apply sequentially.</param>
/// <returns>The transformed string.</returns>
public static string Transform(this string input, params IStringTransformer[] transformers)
{
    var result = input;
    for (int i = 0; i < transformers.Length; i++)
    {
        result = transformers[i].Transform(result);
    }
    return result;
}

